114	async function mockEfficacy(
115		page: import('@playwright/test').Page,
116		opts: {
117			compareFn?: (req: Record<string, unknown>) => Record<string, unknown>;
118			rows?: typeof EFFICACY_ROWS;
119		} = {}
120	) {
121		await page.route('/graphql', async (route) => {
122			const body = route.request().postDataJSON() as {
123				query: string;
124				variables?: Record<string, unknown>;
125			};
126			if (body.query.includes('NodeInfo')) {
127				await route.fulfill({
128					status: 200,
129					contentType: 'application/json',
130					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
131				});
132			} else if (body.query.includes('Projects')) {
133				await route.fulfill({
134					status: 200,
135					contentType: 'application/json',
136					body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } } })
137				});
138			} else if (body.query.includes('EfficacyRows') || body.query.includes('efficacyRows')) {
139				await route.fulfill({
140					status: 200,
141					contentType: 'application/json',
142					body: JSON.stringify({ data: { efficacyRows: opts.rows ?? EFFICACY_ROWS } })
143				});
144			} else if (body.query.includes('EfficacyAttempts') || body.query.includes('efficacyAttempts')) {
145				await route.fulfill({
146					status: 200,
147					contentType: 'application/json',
148					body: JSON.stringify({ data: { efficacyAttempts: ATTEMPTS_DETAIL } })
149				});
150			} else if (
151				body.query.includes('ComparisonDispatch') ||
152				body.query.includes('comparisonDispatch')
153			) {
154				const result = opts.compareFn
155					? opts.compareFn(body.variables ?? {})
156					: { id: 'cmp-001', state: 'queued' };
157				await route.fulfill({
158					status: 200,
159					contentType: 'application/json',
160					body: JSON.stringify({ data: { comparisonDispatch: result } })
161				});
162			} else if (body.query.includes('Comparisons')) {
163				await route.fulfill({
164					status: 200,
165					contentType: 'application/json',
166					body: JSON.stringify({ data: { comparisons: [] } })
167				});
168			} else {
169				await route.continue();
170			}
171		});
172	}
